import { ipcMain, dialog, BrowserWindow } from 'electron';
import { z } from 'zod';
import { ApiResult } from './types';
import { backupService } from '../services/BackupService';

export const BackupExportSchema = z.object({
  password: z.string().min(8, 'Password must be at least 8 characters'),
});

export const BackupImportSchema = z.object({
  filePath: z.string(),
  password: z.string(),
});

export function registerBackupHandlers() {
  // Export backup
  ipcMain.handle('backup:export', async (_event, input): Promise<ApiResult<string>> => {
    try {
      const { password } = BackupExportSchema.parse(input);
      const result = await backupService.exportBackup(password);

      if (result.success && result.filePath) {
        return { success: true, data: result.filePath };
      }
      return { success: false, error: result.error || 'Export failed' };
    } catch (error) {
      if (error instanceof z.ZodError) {
        return { success: false, error: error.issues[0]?.message || 'Validation failed' };
      }
      return { success: false, error: error instanceof Error ? error.message : 'Export failed' };
    }
  });

  // Preview backup
  ipcMain.handle('backup:preview', async (_event, input): Promise<ApiResult<unknown>> => {
    try {
      const { filePath, password } = BackupImportSchema.parse(input);
      const result = await backupService.previewBackup(filePath, password);

      if (result.success && result.metadata) {
        return { success: true, data: result.metadata };
      }
      return { success: false, error: result.error || 'Preview failed' };
    } catch (error) {
      if (error instanceof z.ZodError) {
        return { success: false, error: error.issues[0]?.message || 'Validation failed' };
      }
      return { success: false, error: error instanceof Error ? error.message : 'Preview failed' };
    }
  });

  // Import backup
  ipcMain.handle('backup:import', async (_event, input): Promise<ApiResult<void>> => {
    try {
      const { filePath, password } = BackupImportSchema.parse(input);
      const result = await backupService.importBackup(filePath, password);

      if (result.success) {
        return { success: true };
      }
      return { success: false, error: result.error || 'Import failed' };
    } catch (error) {
      if (error instanceof z.ZodError) {
        return { success: false, error: error.issues[0]?.message || 'Validation failed' };
      }
      return { success: false, error: error instanceof Error ? error.message : 'Import failed' };
    }
  });

  // Select backup file
  ipcMain.handle('backup:selectFile', async (): Promise<ApiResult<string>> => {
    try {
      const parentWindow =
        BrowserWindow.getFocusedWindow() || BrowserWindow.getAllWindows()[0] || null;

      const result = parentWindow
        ? await dialog.showOpenDialog(parentWindow, {
            title: 'Select Backup File',
            properties: ['openFile'],
            filters: [{ name: 'ServerCompass Backup', extensions: ['scbackup'] }],
          })
        : await dialog.showOpenDialog({
            title: 'Select Backup File',
            properties: ['openFile'],
            filters: [{ name: 'ServerCompass Backup', extensions: ['scbackup'] }],
          });

      if (result.canceled || result.filePaths.length === 0) {
        return { success: false, error: 'File selection canceled' };
      }

      return { success: true, data: result.filePaths[0] };
    } catch (error) {
      return {
        success: false,
        error: error instanceof Error ? error.message : 'File selection failed',
      };
    }
  });
}
